"use strict";(globalThis.webpackChunkopenember_docs=globalThis.webpackChunkopenember_docs||[]).push([[418],{930(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"openember-docs-site","metadata":{"permalink":"/en/blog/openember-docs-site","editUrl":"https://github.com/openember/openember-docs/tree/main/blog/2026-04-01-openember-docs-site/index.md","source":"@site/i18n/en/docusaurus-plugin-content-blog/2026-04-01-openember-docs-site/index.md","title":"Welcome to the OpenEmber documentation site","description":"This site is built with Docusaurus and explains what OpenEmber and EmberLite are, how the architecture is layered, how to build each repository, and how the ember CLI fits in.","date":"2026-04-01T00:00:00.000Z","tags":[{"inline":false,"label":"OpenEmber","permalink":"/en/blog/tags/openember","description":"OpenEmber \u4e3b\u6846\u67b6\u4e0e\u5206\u5e03\u5f0f\u8fd0\u884c\u65f6"},{"inline":false,"label":"EmberLite","permalink":"/en/blog/tags/emberlite","description":"EmberLite \u7eaf C \u8f7b\u91cf\u6846\u67b6"},{"inline":false,"label":"\u6587\u6863","permalink":"/en/blog/tags/docs","description":"\u6587\u6863\u7ad9\u70b9\u4e0e\u5199\u4f5c"}],"readingTime":0.46,"hasTruncateMarker":true,"authors":[{"name":"Lu Huadong","title":"Embedded Systems Engineer, Founder of OpenEmber","url":"https://linkedin.com/in/luhuadong","page":{"permalink":"/en/blog/authors/luhuadong"},"socials":{"linkedin":"https://www.linkedin.com/in/luhuadong/","github":"https://github.com/luhuadong","newsletter":"https://luhuadong.com"},"imageURL":"https://github.com/luhuadong.png","key":"luhuadong"}],"frontMatter":{"slug":"openember-docs-site","title":"Welcome to the OpenEmber documentation site","authors":["luhuadong"],"tags":["openember","emberlite","docs"]},"unlisted":false,"nextItem":{"title":"Why EmberLite?","permalink":"/en/blog/why-emberlite"}},"content":"This site is built with [Docusaurus](https://docusaurus.io/) and explains what **OpenEmber** and **EmberLite** are, how the architecture is layered, how to build each repository, and how the **`ember`** CLI fits in.\\n\\n\x3c!-- truncate --\x3e\\n\\nUnder **Docs** you will find:\\n\\n- How OpenEmber relates to EmberLite  \\n- A high-level architecture overview  \\n- Build instructions for the main tree and EmberLite  \\n- Common `ember` commands and environment management (`add` / `use` / `list`)  \\n\\nThe ecosystem is evolving quickly\u2014if you spot gaps or want new topics, please open an issue or PR on [openember-docs](https://github.com/openember/openember-docs)."},{"id":"why-emberlite","metadata":{"permalink":"/en/blog/why-emberlite","editUrl":"https://github.com/openember/openember-docs/tree/main/blog/2026-04-01-why-emberlite/index.md","source":"@site/i18n/en/docusaurus-plugin-content-blog/2026-04-01-why-emberlite/index.md","title":"Why EmberLite?","description":"Even with OpenEmber (C++-first), we still need EmberLite in pure C: industrial, medical, and aerospace projects often prioritize determinism, static memory, and certifiability over language features. C keeps call graphs and resource usage easier to reason about and aligns well with MISRA-style rules.","date":"2026-04-01T00:00:00.000Z","tags":[{"inline":false,"label":"EmberLite","permalink":"/en/blog/tags/emberlite","description":"EmberLite \u7eaf C \u8f7b\u91cf\u6846\u67b6"},{"inline":false,"label":"OpenEmber","permalink":"/en/blog/tags/openember","description":"OpenEmber \u4e3b\u6846\u67b6\u4e0e\u5206\u5e03\u5f0f\u8fd0\u884c\u65f6"}],"readingTime":0.48,"hasTruncateMarker":true,"authors":[{"name":"Lu Huadong","title":"Embedded Systems Engineer, Founder of OpenEmber","url":"https://linkedin.com/in/luhuadong","page":{"permalink":"/en/blog/authors/luhuadong"},"socials":{"linkedin":"https://www.linkedin.com/in/luhuadong/","github":"https://github.com/luhuadong","newsletter":"https://luhuadong.com"},"imageURL":"https://github.com/luhuadong.png","key":"luhuadong"}],"frontMatter":{"slug":"why-emberlite","title":"Why EmberLite?","authors":["luhuadong"],"tags":["emberlite","openember"]},"unlisted":false,"prevItem":{"title":"Welcome to the OpenEmber documentation site","permalink":"/en/blog/openember-docs-site"}},"content":"Even with OpenEmber (C++-first), we still need **EmberLite** in **pure C**: industrial, medical, and aerospace projects often prioritize **determinism**, **static memory**, and **certifiability** over language features. C keeps call graphs and resource usage easier to reason about and aligns well with MISRA-style rules.\\n\\n\x3c!-- truncate --\x3e\\n\\nEmberLite is not meant to replace ROS2 or OpenEmber\u2014it gives resource-constrained embedded Linux devices a lightweight node model and pub/sub messaging while staying on the same **Kconfig + CMake** and **`ember` CLI** workflow, so teams can switch repos without relearning tooling.\\n\\nRead more in the [Introduction](/docs/intro)."}]}}')}}]);